const body = $json || {};

return [
  {
    json: {
      tech_limit: body.tech_limit ?? 36,

      // Market
      symbols: body.symbols ?? "^FCHI,BNP.PA,AIR.PA,MC.PA,OR.PA,ORA.PA",
      interval: body.interval ?? "1d",
      period: body.period ?? "1y",
    },
  },
];

// Réponse brute de l'API backend /tech/watch/latest
const resp = $json || {};

const status = resp.status || "unknown";
const count = resp.count ?? 0;
const items = Array.isArray(resp.items) ? resp.items : [];

// Comptage Hot / Trending / Fresh
let hot = 0;
let trending = 0;
let fresh = 0;

for (const it of items) {
  const rl = String(it.rank_label || "");
  if (rl.startsWith("🔥")) hot++;
  else if (rl.startsWith("⭐")) trending++;
  else fresh++;
}

// Métriques pour le radar
const sourcesTotal = count;
const sourcesOk = count;
const sourcesError = 0;
const nbOk = count;
const nbErr = 0;
const duration = resp.duration || null;
const truncated = false;

// Niveau de qualité global
let quality = "Inconnu";
if (status === "ok" && sourcesTotal > 0) {
  quality = "✅ Complet";
} else if (status === "ok" && sourcesTotal === 0) {
  quality = "⚠️ Vide";
} else if (status === "error") {
  quality = "❌ Échec";
}

// Headline lisible
let headline = "État de la veille inconnu.";
if (sourcesTotal > 0) {
  headline = `Veille chargée : ${sourcesOk}/${sourcesTotal} sources actives.`;
  if (hot > 0 || trending > 0) {
    headline += ` ${hot} Hot · ${trending} Trending.`;
  }
}

// ---- NOUVEAU : on construit une liste "top_items" compacte ----

// On trie les items par score_24h (plus récent / plus chaud)
const sorted = [...items].sort((a, b) => {
  const sA = a.score_24h ?? 0;
  const sB = b.score_24h ?? 0;
  return sB - sA;
});

// On garde seulement les 15 premières sources
const TOP_N = 15;
const topItems = sorted.slice(0, TOP_N).map(it => ({
  block: it.block,
  block_label: it.block_label,
  source_name: it.source_name,
  url: it.url,
  lang: it.lang,
  created_at: it.created_at,
  rank_label: it.rank_label,
  score_24h: it.score_24h,
  freshness: it.freshness,
  favicon_url: it.favicon_url,
}));

return [
  {
    json: {
      type: "tech_radar",
      status,
      quality,
      headline,
      metrics: {
        nb_ok: nbOk,
        nb_err: nbErr,
        sources_total: sourcesTotal,
        sources_ok: sourcesOk,
        sources_error: sourcesError,
        duration_sec: duration,
        truncated,
        hot,
        trending,
        fresh,
      },
      fetched_at: new Date().toISOString(),

      // 👇 au lieu de "raw" énorme, on expose seulement ce qui est utile
      top_items: topItems,
    },
  },
];

const { symbols, interval, period } = $json;

const list = (symbols || "")
  .split(",")
  .map(s => s.trim())
  .filter(s => s.length > 0);

return list.map(sym => ({
  json: {
    symbol: sym,
    interval: interval || "1d",
    period: period || "6mo",
  },
}));

// On récupère tout ce qui arrive depuis HTTP OHLCV
const ohlcvItems = $input.all();

// On transforme chaque item pour garder un objet propre par actif
const assets = ohlcvItems.map(i => {
  const j = i.json || {};

  const candles = j.candles || [];
  const nbCandles = Array.isArray(candles) ? candles.length : 0;
  const lastCandle = nbCandles > 0 ? candles[nbCandles - 1] : null;
  const lastClose = lastCandle ? lastCandle.close : null;

  return {
    symbol: j.symbol,
    interval: j.interval,
    period: j.period,
    source: j.source || "yfinance",
    warning: j.warning || null,
    nb_candles: nbCandles,
    last_close: lastClose,
  };
});

// On renvoie UN SEUL item, avec un champ json = { ... }
return [
  {
    json: {
      status: "ok",
      nb_assets: assets.length,
      assets,
    },
  },
];

const mergedItems = $input.all();
const merged = mergedItems.length > 0 ? mergedItems[0].json : null;

let tech = null;
let market = [];

if (merged) {
  tech = {
    type: merged.type,
    status: merged.status,
    quality: merged.quality,
    headline: merged.headline,
    metrics: merged.metrics,
    fetched_at: merged.fetched_at,
    raw: merged.raw,
  };

  market = [
    {
      status: "ok",
      nb_assets: merged.nb_assets || 0,
      assets: merged.assets || [],
    },
  ];
}

return [
  {
    json: {
      workflow: "StormCopilot Daily Full",
      generated_at: new Date().toISOString(),
      tech_radar: tech,
      market_radar: market,
    },
  },
];
